const items = $input.all();
const transformed = items.map(item => {
  const d = item.json;

  // Rename fields for Airtable compatibility
  const record = {
    'Sync ID': `PG-${d.id}`,
    'Name': d.customer_name ? d.customer_name.trim().replace(/\s+/g, ' ') : '',
    'Email': d.customer_email ? d.customer_email.toLowerCase().trim() : '',
    'Category': mapCategory(d.product_category),
    'Status': mapStatus(d.order_status),
    'Amount': Math.round(parseFloat(d.order_amount) * 100) / 100,
    'Order Date': formatDate(d.order_date),
    'Source': 'PostgreSQL',
    'Last Modified': new Date().toISOString(),
    'ETL Run ID': $('Set Date Range Parameters').first().json.etl_run_id,
    'pg_id': d.id,
    'is_new': new Date(d.created_at) >= new Date($('Set Date Range Parameters').first().json.start_date)
  };

  return { json: record };
});

function mapCategory(pgCategory) {
  const mapping = {
    'electronics': 'Electronics & Tech',
    'clothing': 'Apparel & Fashion',
    'food': 'Food & Beverage',
    'home': 'Home & Garden',
    'sports': 'Sports & Outdoors',
    'books': 'Books & Media'
  };
  return mapping[pgCategory?.toLowerCase()] || pgCategory || 'Uncategorized';
}

function mapStatus(pgStatus) {
  const mapping = {
    'pending': 'Pending',
    'processing': 'In Progress',
    'shipped': 'Shipped',
    'delivered': 'Completed',
    'cancelled': 'Cancelled',
    'refunded': 'Refunded'
  };
  return mapping[pgStatus?.toLowerCase()] || pgStatus || 'Unknown';
}

function formatDate(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  return d.toISOString().split('T')[0];
}

return transformed;

const items = $input.all();

const aggregates = {
  total_records: items.length,
  new_records: items.filter(i => i.json.is_new).length,
  updated_records: items.filter(i => !i.json.is_new).length,
  total_revenue: 0,
  avg_order_value: 0,
  by_category: {},
  by_status: {},
  date: $('Set Date Range Parameters').first().json.start_date,
  etl_run_id: $('Set Date Range Parameters').first().json.etl_run_id
};

for (const item of items) {
  const d = item.json;
  aggregates.total_revenue += d.Amount || 0;

  if (!aggregates.by_category[d.Category]) {
    aggregates.by_category[d.Category] = { count: 0, revenue: 0 };
  }
  aggregates.by_category[d.Category].count++;
  aggregates.by_category[d.Category].revenue += d.Amount || 0;

  if (!aggregates.by_status[d.Status]) {
    aggregates.by_status[d.Status] = 0;
  }
  aggregates.by_status[d.Status]++;
}

aggregates.avg_order_value = aggregates.total_records > 0
  ? Math.round((aggregates.total_revenue / aggregates.total_records) * 100) / 100
  : 0;
aggregates.total_revenue = Math.round(aggregates.total_revenue * 100) / 100;

return [{ json: aggregates }];

const aggregates = $('Calculate Daily Aggregates').first().json;
const upsertResult = $('Upsert Records to Airtable').all();

const categoryRows = Object.entries(aggregates.by_category)
  .map(([cat, data]) => `  - ${cat}: ${data.count} orders ($${data.revenue.toFixed(2)})`)
  .join('\n');

const statusRows = Object.entries(aggregates.by_status)
  .map(([status, count]) => `  - ${status}: ${count}`)
  .join('\n');

const report = {
  subject: `DataSync Pro ETL Report - ${aggregates.date}`,
  html: `
<h2>DataSync Pro - Daily ETL Report</h2>
<p><strong>Run ID:</strong> ${aggregates.etl_run_id}</p>
<p><strong>Date:</strong> ${aggregates.date}</p>

<h3>Summary</h3>
<table border="1" cellpadding="8" cellspacing="0">
  <tr><td>Total Records Processed</td><td><strong>${aggregates.total_records}</strong></td></tr>
  <tr><td>New Records</td><td>${aggregates.new_records}</td></tr>
  <tr><td>Updated Records</td><td>${aggregates.updated_records}</td></tr>
  <tr><td>Total Revenue</td><td>$${aggregates.total_revenue.toFixed(2)}</td></tr>
  <tr><td>Average Order Value</td><td>$${aggregates.avg_order_value.toFixed(2)}</td></tr>
</table>

<h3>By Category</h3>
<pre>${categoryRows}</pre>

<h3>By Status</h3>
<pre>${statusRows}</pre>

<p><em>This is an automated report from DataSync Pro ETL Pipeline.</em></p>
  `
};

return [{ json: report }];

const error = $input.first();
return [{
  json: {
    workflow: 'PostgreSQL ETL Pipeline',
    error_message: error.json.message || 'ETL pipeline failed',
    error_node: error.json.node || 'Unknown',
    timestamp: new Date().toISOString(),
    etl_run_id: $('Set Date Range Parameters').first().json.etl_run_id || 'unknown'
  }
}];

